import{_ as a,c as n,a as c,o as r}from"./app-BawzPSkS.js";const l={};function d(i,e){return r(),n("div",null,e[0]||(e[0]=[c('<blockquote><p>All in AI，看见未来。 每天精选最值得读的AI文章，帮你筛掉时代的噪音。 以简讯见广度，以深读见洞察。 技术、趋势、思考，一站式掌握AI世界。 欢迎关注公众号「AI Reading Hub」，获取更多AI资讯和技术文章。</p></blockquote><h1 id="_2026-03-10-资讯日报" tabindex="-1"><a class="header-anchor" href="#_2026-03-10-资讯日报"><span>2026-03-10 资讯日报</span></a></h1><h2 id="新闻资讯" tabindex="-1"><a class="header-anchor" href="#新闻资讯"><span>新闻资讯</span></a></h2><h3 id="a16z-openclaw开启通用agent时代" tabindex="-1"><a class="header-anchor" href="#a16z-openclaw开启通用agent时代"><span>a16z：OpenClaw开启通用Agent时代</span></a></h3><p>a16z发布全球AI产品Top100更新，ChatGPT领先但竞争激烈，Gemini、Claude增速快。市场碎片化，创意领域巨头入侵，通用Agent涌现，AI嵌入更多工具，排名方式需演进。<a href="https://mp.weixin.qq.com/s?__biz=Mzg5NTc0MjgwMw==&amp;chksm=c1e103971811c33c146d740827448a90b3634dbacc899e57a586b9cf7ec8cfccdb6ce8955725&amp;idx=1&amp;mid=2247523221&amp;sn=06a9fb306371c93d54227d138bb280a4#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="腾讯急推3只龙虾-加速龙虾生态布局" tabindex="-1"><a class="header-anchor" href="#腾讯急推3只龙虾-加速龙虾生态布局"><span>腾讯急推3只龙虾，加速龙虾生态布局</span></a></h3><p>龙虾（OpenClaw）爆火，引发各方关注。院士称大家急着入局，周鸿祎要推一键安装版。腾讯急了，推出3只龙虾，如企业微信接入、WorkBuddy远程控制、QClaw内测，让AI干活更便捷。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cf1d952d56667b6df55afc47c925738868d4036adc164ab66ae625c5b936863973dde8edfd8b&amp;idx=1&amp;mid=2247525892&amp;sn=9d793be50778d1df108d1e92d2e1c1ef#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="ai视频竞演11部作品入围深圳路演" tabindex="-1"><a class="header-anchor" href="#ai视频竞演11部作品入围深圳路演"><span>AI视频竞演11部作品入围深圳路演</span></a></h3><p>3月8日，“无限可能”AI视频竞演二阶段评审结束，11部作品从50部中脱颖而出，晋级3月14日深圳路演大会。作品经专业测评，结果将现场揭晓，还会颁发荣誉与扶持资金。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3OTQyMDE4NA==&amp;chksm=ceb594f8cab2bca35f5621b0226707505c484540044232ad82f76ec1a64680374756e23bfc2b&amp;idx=3&amp;mid=2247603292&amp;sn=2dff8669030de2525c51d0db7b882194#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="_2026北京科幻博览会即将启幕" tabindex="-1"><a class="header-anchor" href="#_2026北京科幻博览会即将启幕"><span>2026北京科幻博览会即将启幕</span></a></h3><p>2026北京国际科幻与未来产业博览会将启幕。它依托科幻大会十年积淀，设四大展区展示前沿成果，超百家企业参与，既推动产业融合，也让科幻走近大众，报名通道已开。<a href="https://mp.weixin.qq.com/s?__biz=MzA4MjEyNzQyMw==&amp;chksm=86a2daf5945e14dadbece75c9ee7a98345f5866e8e7ed4eb2209b3a282fd669835d04d5e6cf4&amp;idx=1&amp;mid=2649902151&amp;sn=c65b78629c6bc0786479a7fbe020b7b0#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="block裁员4000人-ai成裁员遮羞布" tabindex="-1"><a class="header-anchor" href="#block裁员4000人-ai成裁员遮羞布"><span>Block裁员4000人，AI成裁员遮羞布？</span></a></h3><p>Block联合创始人Jack Dorsey称用AI提效而裁员4000人，股价因此上涨。但专家认为AI未大规模提效，裁员或因人员和财务问题。白领工作受AI冲击，Debbie建议做好财务规划，拥抱AI。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f046bcf673fff4e83bdc0fa0e7d931abc76c3d467e36cde835d453113a8326a8f0b8eef9b963&amp;idx=2&amp;mid=2652681777&amp;sn=99ff59555ace8f921a022a1a2ab5ef0a#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="jeff-dean-未来开发者人均50个智能体" tabindex="-1"><a class="header-anchor" href="#jeff-dean-未来开发者人均50个智能体"><span>Jeff Dean：未来开发者人均50个智能体</span></a></h3><p>Jeff Dean：未来开发者人均50个智能体，写需求成核心技能；蒸馏使小模型接近大模型性能；多模态要理解‘非人类’模态；低延迟和个性化模型将极其重要。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e9dea55da10c78b3b0950ff941f21bfb228f86598e4f5a0b0dec8c97f724fd90c0eec3c7c4bd&amp;idx=2&amp;mid=2247873238&amp;sn=eb8d32795e0541a224da484e2dedc9a8#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="首创郎园运营aigc视听产业创新中心" tabindex="-1"><a class="header-anchor" href="#首创郎园运营aigc视听产业创新中心"><span>首创郎园运营AIGC视听产业创新中心</span></a></h3><p>北京AIGC视听产业创新中心：由首创郎园运营，汇聚近百家伙伴，提供多服务平台。携手华为等企业构建产业链生态，片区影视后期企业占超60%市场份额，引领科技文化发展。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3OTQyMDE4NA==&amp;chksm=ce19a472591d3bf4fca37abd333b38502cedeb65625b823c2ea528a771826502f08d889aef48&amp;idx=2&amp;mid=2247603292&amp;sn=c193abc4b2a9cdb36ed27a2197f56af6#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="美军用ai-24小时锁定伊朗1000目标" tabindex="-1"><a class="header-anchor" href="#美军用ai-24小时锁定伊朗1000目标"><span>美军用AI 24小时锁定伊朗1000目标</span></a></h3><p>美军在美伊冲突中，让Claude与Maven系统合作，24小时锁定1000个目标。Maven成美军依赖的“战争操作系统”，AI让战争节奏改变，未来或走向“机器生成、人类确认”模式。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f0c336aeee43d330b58f5cdf4315b8173b4d26e100c6a38e92bf082290ca1ef011b7379e8b06&amp;idx=2&amp;mid=2652681809&amp;sn=96ca2a9e7ebfc12343f50ae6a85d3be2#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="产品应用" tabindex="-1"><a class="header-anchor" href="#产品应用"><span>产品应用</span></a></h2><h3 id="微软copilot-cowork-claude接管office全家桶" tabindex="-1"><a class="header-anchor" href="#微软copilot-cowork-claude接管office全家桶"><span>微软Copilot Cowork：Claude接管Office全家桶</span></a></h3><p>微软推出Copilot Cowork，内置Claude模型，全面接管Office。它能执行任务，处理多种办公场景。微软采用多模型策略，抛弃OpenAI。产品适合企业，价格较高，AI智能体时代正来临。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f0a3ec4ef70c124878df956b7b9d7605db10d1b38da6dbcb19e075064e249637c1483d8fe921&amp;idx=1&amp;mid=2652681777&amp;sn=27f2a164dbc8a5e43525db9e448b6cea#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="clawforce助力openclaw走向企业应用" tabindex="-1"><a class="header-anchor" href="#clawforce助力openclaw走向企业应用"><span>ClawForce助力OpenClaw走向企业应用</span></a></h3><p>OpenClaw个人用户多，企业应用少。MemTensor团队的ClawForce可自动配置Agent，复刻销冠打法，有管控审计。它让AI成组织神经系统，助力OpenClaw走向企业化。<a href="https://mp.weixin.qq.com/s?__biz=MzkxNjcyNTk2NA==&amp;chksm=c073e07820d65038b9527694491b1e3539b056914b0697d7b80ff4b9c203d7baec7112effb1a&amp;idx=1&amp;mid=2247490670&amp;sn=4b23000e07a9a6ed11bae799951f399b#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="arthas-agent-让java排障一句话搞定" tabindex="-1"><a class="header-anchor" href="#arthas-agent-让java排障一句话搞定"><span>Arthas Agent：让Java排障一句话搞定</span></a></h3><p>甄新团队推出的Arthas Agent，让Java排障更简单。用户描述现象，它自动匹配技能、生成命令、收敛证据并输出报告，避免传统排障的高门槛和高耗时，还给出使用及提效方法。<a href="https://mp.weixin.qq.com/s?__biz=MzIzOTU0NTQ0MA==&amp;chksm=e85b80d1c6a1f650ea46ded4ca4b8370c3b23e85184a7e456f655e87c593d46a97f691ccfad8&amp;idx=1&amp;mid=2247558779&amp;sn=b528bc344afbf76933f5b1b13041ff67#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="claude推多智能体代码审查系统抓bug" tabindex="-1"><a class="header-anchor" href="#claude推多智能体代码审查系统抓bug"><span>Claude推多智能体代码审查系统抓Bug</span></a></h3><p>Anthropic：为Claude Code引入代码审查系统，调度多智能体揪深层Bug。此系统审查更彻底，内部部署后有效提升审查质量。开发者可自定义规则，管理员能管控成本。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3MTkxMjYzOA==&amp;chksm=cf2eac9ec534e9c9fb4395b45253c6ddd42efaf34b94e22f6ba0549e899fd55d65707b9650ac&amp;idx=1&amp;mid=2247513209&amp;sn=d733eb25c36ff283cb2d8bd3d9f5d56f#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="openclaw更新-安全认证与部署回滚能力提升" tabindex="-1"><a class="header-anchor" href="#openclaw更新-安全认证与部署回滚能力提升"><span>OpenClaw更新：安全认证与部署回滚能力提升</span></a></h3><p>OpenClaw 2026.3.8更新：ACP来源验证让代理确认指令源，更新前自动备份配置可回滚，还修复多项问题。虽功能与安全提升，但也带来升级负担。<a href="https://mp.weixin.qq.com/s?__biz=MzA5MTIxNTY4MQ==&amp;chksm=868f8ec94e31607e1fdad4788d71fa825a87d1e34078bcdb8a917a6bf908e056c9141dc3416e&amp;idx=1&amp;mid=2461158789&amp;sn=0e7757bc0939894b25acb89107c23bf2#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="智谱澳龙-1分钟开启agent时代" tabindex="-1"><a class="header-anchor" href="#智谱澳龙-1分钟开启agent时代"><span>智谱澳龙：1分钟开启Agent时代</span></a></h3><p>智谱推出AutoClaw（澳龙）应用，安装使用仅1分钟，无需配置。可切换多模型，预置50多技能，能一键接入飞书。它降低OpenClaw使用门槛，让普通人也能进入Agent时代。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e9504efe308a0623a0831201237a7aef0ae7acbd9cafcc9d33cf78f0292870cb4cdaa2525551&amp;idx=1&amp;mid=2247873238&amp;sn=9f35ccb5f5b48e67adfe36d20636d5da#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="智谱发布autoclaw-终结openclaw安装难题" tabindex="-1"><a class="header-anchor" href="#智谱发布autoclaw-终结openclaw安装难题"><span>智谱发布AutoClaw，终结OpenClaw安装难题</span></a></h3><p>智谱：发布AutoClaw将OpenClaw打包成一键安装应用，解决安装难题。内置Pony - Alpha - 2模型，支持热插拔和飞书集成，50 + 技能开箱即用，还启动‘小龙虾敲门计划’免费帮装。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f0ee76b8f604241e11dd84fb872bd9907e0fb9f3d4bd720553ceb732928da18d85909712b9ff&amp;idx=1&amp;mid=2652681809&amp;sn=59d48990144e7d166b789b29d8b61fe0#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="智谱autoclaw-最傻瓜的openclaw安装法" tabindex="-1"><a class="header-anchor" href="#智谱autoclaw-最傻瓜的openclaw安装法"><span>智谱AutoClaw：最傻瓜的OpenClaw安装法</span></a></h3><p>数字生命卡兹克：智谱AutoClaw是最傻瓜的OpenClaw安装方式，本地部署，配置简单，优化技能，支持多模型API，还能建分身，让普通人感受Agent魅力，值得一试。<a href="https://mp.weixin.qq.com/s?__biz=MzIyMzA5NjEyMA==&amp;chksm=f15469077ad99529a5c0922494268fabbf4d8d2d68a0c23f7b66d65e6455a44974e0d38a1192&amp;idx=1&amp;mid=2647680547&amp;sn=1435bf3cfc3a5aebf18f75ffdce55b21#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="boss直聘3b小模型比肩80b大模型" tabindex="-1"><a class="header-anchor" href="#boss直聘3b小模型比肩80b大模型"><span>BOSS直聘3B小模型比肩80B大模型</span></a></h3><p>BOSS直聘楠北阁团队发布Nanbeige4.1-3B小模型，性能惊人。团队通过重构数据、优化训练、采用强化学习等方法，提升其多方面能力，在多项测试中超越大模型，展现小模型大潜力。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cf2cfdf9293a26f114bfdc8d637e103bc08e2fe7a547312e7debbeb522b114f2d0abd2a91545&amp;idx=3&amp;mid=2247525892&amp;sn=72991bca21da24c439883e3642a4a369#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="开源动态" tabindex="-1"><a class="header-anchor" href="#开源动态"><span>开源动态</span></a></h2><h3 id="浙大等推skillnet-ai智能体告别失忆" tabindex="-1"><a class="header-anchor" href="#浙大等推skillnet-ai智能体告别失忆"><span>浙大等推SkillNet，AI智能体告别失忆</span></a></h3><p>浙江大学等推出SkillNet，含超20万个Skills。它解决AI智能体处理复杂任务痛点，构建Skills网络，经多维度评估，在仿真环境和实际场景表现优异，优于传统平台。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cff89ebcd51b0ac54ea3fc8b237f0b145d0dfdd4e9e65ad7504e689ace3e656294382797be21&amp;idx=2&amp;mid=2247525892&amp;sn=1b8695c95f9cc1bebb737687e79df75f#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="karpathy-agent将接管大模型研发" tabindex="-1"><a class="header-anchor" href="#karpathy-agent将接管大模型研发"><span>Karpathy：Agent将接管大模型研发</span></a></h3><p>Andrej Karpathy：新项目autoresearch让AI改代码，经微调找到降低验证损失的修改，提升排行榜成绩。Agent发现重要改进点，前沿LLM实验室未来或用此自动化研究。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3MTkxMjYzOA==&amp;chksm=cf5e463bc527de78f6496790e976beb18270eef161787e31dc2e427c0af4a81128b543b13942&amp;idx=1&amp;mid=2247513200&amp;sn=0a2c3b157e7c0c499c0a396ab629bfbe#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="openclaw必装10个skills实战教程" tabindex="-1"><a class="header-anchor" href="#openclaw必装10个skills实战教程"><span>OpenClaw必装10个Skills实战教程</span></a></h3><p>文章指出，OpenClaw作为开源AI智能体，可通过Skills系统执行复杂任务。作者整理10个必装Skills，如实时联网神器、浏览器自动化等，提供安装、配置和实战案例，还给出常见问题解答和学习资源，助用户提升效率。<a href="https://mp.weixin.qq.com/s?__biz=MzA4MTk3ODI2OA==&amp;chksm=86777c4f5d0b27fa6edf1f69a7d7190e98b74ac9fc9b204220820e64e6daf229f571fee18f80&amp;idx=1&amp;mid=2650364580&amp;sn=7394a7e9506ad848aa8571fd7b84b114#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="算法论文" tabindex="-1"><a class="header-anchor" href="#算法论文"><span>算法论文</span></a></h2><h3 id="linvideo-加速视频扩散模型推理-降低成本" tabindex="-1"><a class="header-anchor" href="#linvideo-加速视频扩散模型推理-降低成本"><span>LINVIDEO：加速视频扩散模型推理，降低成本</span></a></h3><p>香港科技大学等团队提出LINVIDEO框架，解决视频扩散模型线性化难题。通过选择性迁移和ADM，在不重新预训练下，实现1.71 - 20.9倍加速，保持视频生成质量。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e9e54251d12c41aa76a10feb84ed2a157c3a8397c31a7f18eda0dce13e0a1dea230abb0476be&amp;idx=3&amp;mid=2247873238&amp;sn=d8efab75deb200ea1fffa00ee8ae8942#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="dragstream-开启视频流式拖拽编辑新时代" tabindex="-1"><a class="header-anchor" href="#dragstream-开启视频流式拖拽编辑新时代"><span>DragStream：开启视频流式拖拽编辑新时代</span></a></h3><p>新加坡南洋理工大学和合肥工大团队：提出REVEL任务，用DragStream方法实现视频实时拖拽编辑，免训练、适配性强，实验效果超SOTA，打破低效循环，推动AIGC视频创作。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f0faa16b5796bb28b0efd8d87e22c14909c17c54eb23546d1e31159a41d119e8ad0ec3fff5db&amp;idx=3&amp;mid=2652681809&amp;sn=6d8adc67b8cec4920bac8732b0c892fc#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="微软等提出-aro-优化器-训练提速-1-3" tabindex="-1"><a class="header-anchor" href="#微软等提出-aro-优化器-训练提速-1-3"><span>微软等提出 ARO 优化器，训练提速 1/3</span></a></h3><p>微软等团队：提出 ARO 优化器，将梯度旋转作为第一原则，训练效率比 AdamW 提升约 1/3、比 Muon 高 10% - 15%，还能全模型优化，从对称性角度诠释优化。<a href="https://mp.weixin.qq.com/s?__biz=MzA3MzI4MjgzMw==&amp;chksm=85e293fd6324045ca5d2c8e364401638431c926742e1c11a638b853c34e04e603d439c9085aa&amp;idx=2&amp;mid=2651020721&amp;sn=4bdc44d12da02e1c95a39584535ceb60#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="ai-agent用100美元token赚48万美元" tabindex="-1"><a class="header-anchor" href="#ai-agent用100美元token赚48万美元"><span>AI Agent用100美元Token赚48万美元</span></a></h3><p>Humanlaya等机构构建$OneMillion - Bench评测基准，用经济价值衡量模型。目前最强模型能完成48万美元任务，成本仅100美元，但离可交付专业任务还有差距，后续要提升价值稳定性。<a href="https://mp.weixin.qq.com/s?__biz=MzA3MzI4MjgzMw==&amp;chksm=85dea14ac156e311c39588ddca461fb99d28f9cc97f5fefcbb9b7a97a42472fe53864e8fc5dd&amp;idx=1&amp;mid=2651020721&amp;sn=50a4294d143ae2985464ae9ae899fd7e#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><p style="text-align:center;"><img id="weixin_qr" src="https://meikan-public-images.oss-cn-beijing.aliyuncs.com/imeikan/assets/2025-05-18234303-hub.png" style="max-width:800px;object-fit:cover;"></p><p><a href="https://aireadinghub.com/" target="_blank" rel="noopener noreferrer">官网：www.AiReadingHub.com</a></p>',56)]))}const p=a(l,[["render",d]]),s=JSON.parse('{"path":"/posts/2026-03-10.html","title":"AI日报：a16z：OpenClaw开启通用Agent时代; 腾讯急推3只龙虾，加速龙虾生态布局; AI视频竞演11部作品入围深圳路演","lang":"zh-CN","frontmatter":{"date":"2026-03-10T00:00:00.000Z","title":"AI日报：a16z：OpenClaw开启通用Agent时代; 腾讯急推3只龙虾，加速龙虾生态布局; AI视频竞演11部作品入围深圳路演"},"headers":[{"level":2,"title":"新闻资讯","slug":"新闻资讯","link":"#新闻资讯","children":[{"level":3,"title":"a16z：OpenClaw开启通用Agent时代","slug":"a16z-openclaw开启通用agent时代","link":"#a16z-openclaw开启通用agent时代","children":[]},{"level":3,"title":"腾讯急推3只龙虾，加速龙虾生态布局","slug":"腾讯急推3只龙虾-加速龙虾生态布局","link":"#腾讯急推3只龙虾-加速龙虾生态布局","children":[]},{"level":3,"title":"AI视频竞演11部作品入围深圳路演","slug":"ai视频竞演11部作品入围深圳路演","link":"#ai视频竞演11部作品入围深圳路演","children":[]},{"level":3,"title":"2026北京科幻博览会即将启幕","slug":"_2026北京科幻博览会即将启幕","link":"#_2026北京科幻博览会即将启幕","children":[]},{"level":3,"title":"Block裁员4000人，AI成裁员遮羞布？","slug":"block裁员4000人-ai成裁员遮羞布","link":"#block裁员4000人-ai成裁员遮羞布","children":[]},{"level":3,"title":"Jeff Dean：未来开发者人均50个智能体","slug":"jeff-dean-未来开发者人均50个智能体","link":"#jeff-dean-未来开发者人均50个智能体","children":[]},{"level":3,"title":"首创郎园运营AIGC视听产业创新中心","slug":"首创郎园运营aigc视听产业创新中心","link":"#首创郎园运营aigc视听产业创新中心","children":[]},{"level":3,"title":"美军用AI 24小时锁定伊朗1000目标","slug":"美军用ai-24小时锁定伊朗1000目标","link":"#美军用ai-24小时锁定伊朗1000目标","children":[]}]},{"level":2,"title":"产品应用","slug":"产品应用","link":"#产品应用","children":[{"level":3,"title":"微软Copilot Cowork：Claude接管Office全家桶","slug":"微软copilot-cowork-claude接管office全家桶","link":"#微软copilot-cowork-claude接管office全家桶","children":[]},{"level":3,"title":"ClawForce助力OpenClaw走向企业应用","slug":"clawforce助力openclaw走向企业应用","link":"#clawforce助力openclaw走向企业应用","children":[]},{"level":3,"title":"Arthas Agent：让Java排障一句话搞定","slug":"arthas-agent-让java排障一句话搞定","link":"#arthas-agent-让java排障一句话搞定","children":[]},{"level":3,"title":"Claude推多智能体代码审查系统抓Bug","slug":"claude推多智能体代码审查系统抓bug","link":"#claude推多智能体代码审查系统抓bug","children":[]},{"level":3,"title":"OpenClaw更新：安全认证与部署回滚能力提升","slug":"openclaw更新-安全认证与部署回滚能力提升","link":"#openclaw更新-安全认证与部署回滚能力提升","children":[]},{"level":3,"title":"智谱澳龙：1分钟开启Agent时代","slug":"智谱澳龙-1分钟开启agent时代","link":"#智谱澳龙-1分钟开启agent时代","children":[]},{"level":3,"title":"智谱发布AutoClaw，终结OpenClaw安装难题","slug":"智谱发布autoclaw-终结openclaw安装难题","link":"#智谱发布autoclaw-终结openclaw安装难题","children":[]},{"level":3,"title":"智谱AutoClaw：最傻瓜的OpenClaw安装法","slug":"智谱autoclaw-最傻瓜的openclaw安装法","link":"#智谱autoclaw-最傻瓜的openclaw安装法","children":[]},{"level":3,"title":"BOSS直聘3B小模型比肩80B大模型","slug":"boss直聘3b小模型比肩80b大模型","link":"#boss直聘3b小模型比肩80b大模型","children":[]}]},{"level":2,"title":"开源动态","slug":"开源动态","link":"#开源动态","children":[{"level":3,"title":"浙大等推SkillNet，AI智能体告别失忆","slug":"浙大等推skillnet-ai智能体告别失忆","link":"#浙大等推skillnet-ai智能体告别失忆","children":[]},{"level":3,"title":"Karpathy：Agent将接管大模型研发","slug":"karpathy-agent将接管大模型研发","link":"#karpathy-agent将接管大模型研发","children":[]},{"level":3,"title":"OpenClaw必装10个Skills实战教程","slug":"openclaw必装10个skills实战教程","link":"#openclaw必装10个skills实战教程","children":[]}]},{"level":2,"title":"算法论文","slug":"算法论文","link":"#算法论文","children":[{"level":3,"title":"LINVIDEO：加速视频扩散模型推理，降低成本","slug":"linvideo-加速视频扩散模型推理-降低成本","link":"#linvideo-加速视频扩散模型推理-降低成本","children":[]},{"level":3,"title":"DragStream：开启视频流式拖拽编辑新时代","slug":"dragstream-开启视频流式拖拽编辑新时代","link":"#dragstream-开启视频流式拖拽编辑新时代","children":[]},{"level":3,"title":"微软等提出 ARO 优化器，训练提速 1/3","slug":"微软等提出-aro-优化器-训练提速-1-3","link":"#微软等提出-aro-优化器-训练提速-1-3","children":[]},{"level":3,"title":"AI Agent用100美元Token赚48万美元","slug":"ai-agent用100美元token赚48万美元","link":"#ai-agent用100美元token赚48万美元","children":[]}]}],"git":{"updatedTime":1774327125000,"contributors":[{"name":"GitHub Actions","username":"","email":"actions@github.com","commits":1}],"changelog":[{"hash":"01c7269a618c2012f0dd89988242bab0ef7dfa14","time":1774327125000,"email":"actions@github.com","author":"GitHub Actions","message":"Auto-commit generated files on 2026-03-24T04:38:45.424Z"}]},"filePathRelative":"posts/2026-03-10.md","excerpt":"<blockquote>\\n<p>All in AI，看见未来。 每天精选最值得读的AI文章，帮你筛掉时代的噪音。 以简讯见广度，以深读见洞察。 技术、趋势、思考，一站式掌握AI世界。\\n欢迎关注公众号「AI Reading Hub」，获取更多AI资讯和技术文章。</p>\\n</blockquote>\\n<h1>2026-03-10 资讯日报</h1>\\n<h2>新闻资讯</h2>\\n<h3>a16z：OpenClaw开启通用Agent时代</h3>\\n<p>a16z发布全球AI产品Top100更新，ChatGPT领先但竞争激烈，Gemini、Claude增速快。市场碎片化，创意领域巨头入侵，通用Agent涌现，AI嵌入更多工具，排名方式需演进。<a href=\\"https://mp.weixin.qq.com/s?__biz=Mzg5NTc0MjgwMw==&amp;chksm=c1e103971811c33c146d740827448a90b3634dbacc899e57a586b9cf7ec8cfccdb6ce8955725&amp;idx=1&amp;mid=2247523221&amp;sn=06a9fb306371c93d54227d138bb280a4#rd\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">&gt;阅读原文</a></p>"}');export{p as comp,s as data};
